 1	import React, { useState } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { generatePrettyName } from '@kubevirt-utils/utils/utils';
 5	import {
 6	  Button,
 7	  ButtonVariant,
 8	  Form,
 9	  FormGroup,
10	  FormSection,
11	  Grid,
12	  GridItem,
13	  Popover,
14	  PopoverPosition,
15	  TextInput,
16	} from '@patternfly/react-core';
17	import { HelpIcon } from '@patternfly/react-icons';
18	
19	import CheckupsStorageFormActions from './CheckupsStorageFormActions';
20	
21	import './checkups-storage-form.scss';
22	
23	const CheckupsStorageForm = () => {
24	  const { t } = useKubevirtTranslation();
25	  const [name, setName] = useState<string>(generatePrettyName('kubevirt-storage-checkup'));
26	  const [timeOut, setTimeOut] = useState<string>('10');
27	
28	  return (
29	    <Grid>
30	      <GridItem span={6}>
31	        <Form className={'CheckupsStorageForm--main'}>
32	          <FormSection title={t('Run storage checkup')} titleElement="h1">
33	            {t(
34	              `Storage checkup validating storage is working correctly for VirtualMachines using the kiagnose engine.`,
35	            )}
36	
37	            <FormGroup fieldId="name" isRequired label={t('Name')}>
38	              <TextInput
39	                id="name"
40	                isRequired
41	                name="name"
42	                onChange={(_event, value) => setName(value)}
43	                value={name}
44	              />
45	            </FormGroup>
46	            <FormGroup
47	              labelHelp={
48	                <Popover
49	                  bodyContent={t('How much time before the check will try to close itself')}
50	                  position={PopoverPosition.right}
51	                >
52	                  <Button variant={ButtonVariant.plain}>
53	                    <HelpIcon />
54	                  </Button>
55	                </Popover>
56	              }
57	              fieldId="timeout"
58	              isRequired
59	              label={t('Timeout (minutes)')}
60	            >
61	              <TextInput
62	                className="CheckupsStorageForm--main__number-input"
63	                id="timeout"
64	                isRequired
65	                name="timeout"
66	                onChange={(_event, val) => setTimeOut(val)}
67	                type="number"
68	                value={timeOut}
69	              />
70	            </FormGroup>
71	            <CheckupsStorageFormActions name={name} timeOut={timeOut} />
72	          </FormSection>
73	        </Form>
74	      </GridItem>
75	    </Grid>
76	  );
77	};
78	
79	export default CheckupsStorageForm;

